   const api = new Hono();
   api.route("/scenarios", scenarioRoutes(dataDir));
   api.route("/results", resultRoutes(join(dataDir, "results")));
   api.route("/fanout", fanoutRoutes(dataDir));
   api.route("/run", runRoutes(dataDir));
+
   app.route("/api", api);
